/**
 * seed-questions-400-part2.mjs — Part 2 of 400+ interview questions seeding.
 * Fills underrepresented fields: architecture, droit, tourisme, communication,
 * medecine, pharmacie, plus more for all major fields.
 */

import pg from "pg";
import crypto from "crypto";

const DATABASE_URL =
  process.env.DATABASE_URL ?? "postgresql://postgres:postgres@localhost:5432/postgres";
const client = new pg.Client({ connectionString: DATABASE_URL });

let sortOrder = 620;
function nextSort() { return sortOrder++; }
function uid(prefix) { return `${prefix}-${crypto.randomUUID().slice(0, 8)}`; }

function Q(prefix, question, questionFr, type, field, difficulty, sampleAnswer, sampleAnswerFr, tips, tipsFr) {
  return {
    id: uid(prefix), question, question_fr: questionFr, type, field, difficulty,
    sample_answer: sampleAnswer, sample_answer_fr: sampleAnswerFr,
    tips: JSON.stringify(tips), tips_fr: JSON.stringify(tipsFr),
    is_active: true, sort_order: nextSort(),
  };
}

