// ============================================================================
// INSERT LOGIC
// ============================================================================
async function run() {
  await client.connect();
  console.log(`Connected. Inserting ${QUESTIONS.length} questions (part 2) starting at sort_order ${620}...`);

  const BATCH_SIZE = 50;
  let inserted = 0;
  let skipped = 0;

  for (let i = 0; i < QUESTIONS.length; i += BATCH_SIZE) {
    const batch = QUESTIONS.slice(i, i + BATCH_SIZE);
    const values = [];
    const params = [];
    let paramIdx = 1;

    for (const q of batch) {
      values.push(`($${paramIdx}, $${paramIdx+1}, $${paramIdx+2}, $${paramIdx+3}, $${paramIdx+4}, $${paramIdx+5}, $${paramIdx+6}, $${paramIdx+7}, $${paramIdx+8}, $${paramIdx+9}, $${paramIdx+10}, $${paramIdx+11})`);
      params.push(q.id, q.question, q.question_fr, q.type, q.field, q.sample_answer, q.sample_answer_fr, q.tips, q.tips_fr, q.difficulty, q.is_active, q.sort_order);
      paramIdx += 12;
    }

    const sql = `INSERT INTO interview_common_question (id, question, question_fr, type, field, sample_answer, sample_answer_fr, tips, tips_fr, difficulty, is_active, sort_order)
      VALUES ${values.join(",\n")}
      ON CONFLICT (id) DO NOTHING`;

    const result = await client.query(sql, params);
    inserted += result.rowCount;
    skipped += batch.length - result.rowCount;
    console.log(`  Batch ${Math.floor(i / BATCH_SIZE) + 1}: inserted ${result.rowCount}, skipped ${batch.length - result.rowCount}`);
  }

  const countRes = await client.query("SELECT COUNT(*) as cnt FROM interview_common_question");
  const fieldDist = await client.query("SELECT field, COUNT(*) as cnt FROM interview_common_question GROUP BY field ORDER BY cnt DESC");
  const typeDist = await client.query("SELECT type, COUNT(*) as cnt FROM interview_common_question GROUP BY type ORDER BY cnt DESC");
  const diffDist = await client.query("SELECT difficulty, COUNT(*) as cnt FROM interview_common_question GROUP BY difficulty ORDER BY cnt DESC");

  console.log(`\n=== RESULTS ===`);
  console.log(`Questions in part 2: ${QUESTIONS.length}`);
  console.log(`Inserted: ${inserted}`);
  console.log(`Skipped: ${skipped}`);
  console.log(`Total questions in table: ${countRes.rows[0].cnt}`);
  console.log(`\nField distribution:`);
  for (const row of fieldDist.rows) console.log(`  ${row.field}: ${row.cnt}`);
  console.log(`\nType distribution:`);
  for (const row of typeDist.rows) console.log(`  ${row.type}: ${row.cnt}`);
  console.log(`\nDifficulty distribution:`);
  for (const row of diffDist.rows) console.log(`  ${row.difficulty}: ${row.cnt}`);

  await client.end();
  console.log("\nDone!");
}

run().catch((err) => { console.error("Error:", err); process.exit(1); });
